from cryptography.fernet import Fernet

class CreditCardEncryptor:
    def __init__(self, key):
        self.key = key
        self.cipher = Fernet(key)
    
    def encrypt(self, credit_card_number):
        return self.cipher.encrypt(credit_card_number.encode()).decode()

    def decrypt(self, encrypted_credit_card_number):
        return self.cipher.decrypt(encrypted_credit_card_number.encode()).decode()

